// expense-management.component.ts - VERSIONE CORRETTA
import { Component, OnInit, inject, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subscription } from 'rxjs';
import { ExpenseService, Expense, ExpenseCategory, RecurringExpenseTemplate } from '../../services/Economico/expense.service';
import { SupplierService } from '../../services/supplier.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-expense-management',
  templateUrl: './expense-management.html',
  styleUrls: ['./expense-management.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule]
})
export class ExpenseManagement implements OnInit, OnDestroy {
  private expenseService = inject(ExpenseService);
  private supplierService = inject(SupplierService);

  // Sottoscrizioni per cleanup
  private expenseSubscription!: Subscription;
  private templatesSubscription!: Subscription;
  private categoriesSubscription!: Subscription;
  private suppliersSubscription!: Subscription;

  // Dati
  expenses: Expense[] = [];
  availableMonths: string[] = [];
  categories: ExpenseCategory[] = [];
  suppliers: any[] = [];
  recurringTemplates: RecurringExpenseTemplate[] = [];
  showDeletedExpenses = false;

  // Filtri e stato
  selectedMonth: string = this.getCurrentMonth();
  viewMode: 'monthly' | 'all' = 'monthly';
  searchTerm: string = '';

  // Modals
  showExpenseModal = false;
  showMonthsModal = false;
  showCategoryModal = false;
  showSupplierModal = false;
  editingExpense: Expense | null = null;

  // Stati per gestire la conferma in due fasi
  showFutureMonthsConfirm = false;
  pendingExpenseUpdate: {
    expenseId: string;
    expenseData: any;
    oldTemplateId: string | null;
  } | null = null;

  // Form template ricorrente
  recurringTemplateForm = {
    name: '',
    amount: 0,
    type: 'fissa' as 'fissa' | 'variabile',
    category: '',
    notes: '',
    supplier_id: null as string | null,
    start_month: this.getCurrentMonth(),
    end_month: '' as string | undefined
  };

  // Form data - AGGIUNTA template_id
  expenseForm = {
    name: '',
    amount: 0,
    type: 'fissa' as 'fissa' | 'variabile',
    category: '',
    month: this.getCurrentMonth(),
    notes: '',
    supplier_id: null as string | null,
    template_id: null as string | null  // AGGIUNTO
  };

  // Form categoria
  categoryForm = {
    name: '',
    type: 'entrambi' as 'fissa' | 'variabile' | 'entrambi'
  };

  // Form fornitore
  supplierForm = {
    company_name: '',
    contact_name: '',
    email: '',
    phone: '',
    address: '',
    description: ''
  };

  // Spese Cancellate
  showAllTemplates = false;
  showDeletedSection = false;
  deletedExpenses: Expense[] = [];
  loadingDeleted = false;


  // Statistiche
  get monthlyStats() {
    return this.expenseService.calculateMonthlyTotal(this.filteredExpenses);
  }

  get filteredExpenses(): Expense[] {
    let filtered = this.expenses;

    if (this.viewMode === 'monthly') {
      filtered = filtered.filter(expense =>
        expense.month.startsWith(this.selectedMonth.substring(0, 7))
      );
    }

    if (this.searchTerm) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(expense =>
        expense.name.toLowerCase().includes(term) ||
        expense.category.toLowerCase().includes(term) ||
        (expense.notes && expense.notes.toLowerCase().includes(term))
      );
    }

    return filtered;
  }

  get allCategories(): string[] {
    const defaultCats = this.expenseService.getDefaultCategories();
    const customCats = this.categories.map(cat => cat.name);
    return [...new Set([...defaultCats, ...customCats])].sort();
  }

  getCategoriesByType(type: 'fissa' | 'variabile'): string[] {
    return this.allCategories.filter(cat => {
      const category = this.categories.find(c => c.name === cat);
      if (category) {
        return category.type === 'entrambi' || category.type === type;
      }
      return true;
    });
  }

  async toggleDeletedSection() {
    this.showDeletedSection = !this.showDeletedSection;

    if (this.showDeletedSection && this.deletedExpenses.length === 0) {
      await this.loadDeletedExpenses();
    }
  }

  async loadDeletedExpenses() {
    this.loadingDeleted = true;
    try {
      if (this.viewMode === 'monthly') {
        console.log('🗑️ Loading deleted expenses for month:', this.selectedMonth);
        this.deletedExpenses = await this.expenseService.loadDeletedExpensesForMonth(this.selectedMonth);
      } else {
        console.log('🗑️ Loading ALL deleted expenses');
        this.deletedExpenses = await this.expenseService.loadDeletedExpensesForDateRange('2000-01-01', '2030-12-01');
      }
      console.log('✅ Deleted expenses loaded:', this.deletedExpenses.length);
    } catch (error) {
      console.error('❌ Error loading deleted expenses:', error);
    } finally {
      this.loadingDeleted = false;
    }
  }

  ngOnInit() {
    this.loadData();
  }

  ngOnDestroy() {
    // Cleanup delle sottoscrizioni
    if (this.expenseSubscription) this.expenseSubscription.unsubscribe();
    if (this.templatesSubscription) this.templatesSubscription.unsubscribe();
    if (this.categoriesSubscription) this.categoriesSubscription.unsubscribe();
    if (this.suppliersSubscription) this.suppliersSubscription.unsubscribe();
  }

  async loadData() {
    try {
      console.log('🔍 Loading data for month:', this.selectedMonth);

      // Carica in parallelo
      await Promise.all([
        this.loadExpenses(),
        this.loadAvailableMonths(),
        this.loadCategories(),
        this.loadSuppliers(),
        this.loadRecurringTemplates()
      ]);
    } catch (error) {
      console.error('❌ Error loading data:', error);
    }
  }

  async loadRecurringTemplates() {
    await this.expenseService.loadRecurringTemplates();
    this.templatesSubscription = this.expenseService.recurringTemplates$.subscribe(templates => {
      this.recurringTemplates = templates;
      console.log('📋 Recurring templates loaded:', templates.length);
    });
  }

  async loadSuppliers() {
    await this.supplierService.loadSuppliers();
    this.suppliersSubscription = this.supplierService.suppliers$.subscribe(suppliers => {
      this.suppliers = suppliers;
      console.log('🏢 Suppliers loaded:', suppliers.length);
    });
  }

  async loadExpenses() {
    try {
      if (this.viewMode === 'monthly') {
        console.log('📅 Loading expenses for month:', this.selectedMonth);
        await this.expenseService.loadExpensesForMonth(this.selectedMonth, true);

        this.expenseSubscription = this.expenseService.data$.subscribe(expenses => {
          // Filtra solo le spese non eliminate
          this.expenses = expenses.filter(expense => !expense.deleted_at);
          console.log('💰 Expenses loaded:', this.expenses.length);
        });
      } else {
        console.log('📊 Loading ALL expenses');
        const allExpenses = await this.expenseService.loadExpensesForDateRange('2000-01-01', '2030-12-01');
        // Filtra solo le spese non eliminate
        this.expenses = allExpenses.filter(expense => !expense.deleted_at);
        console.log('📊 All expenses loaded:', this.expenses.length);
      }
    } catch (error) {
      console.error('❌ Error loading expenses:', error);
    }
  }


  async loadAvailableMonths() {
    this.availableMonths = await this.expenseService.getAvailableMonths();
    console.log('📆 Available months:', this.availableMonths.length);
  }

  async loadCategories() {
    await this.expenseService.loadCategories();
    this.categoriesSubscription = this.expenseService.categories$.subscribe(categories => {
      this.categories = categories;
      console.log('🏷️ Categories loaded:', categories.length);
    });
  }

  // Metodi per gestione data
  getCurrentMonth(): string {
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  }

  formatMonthForInput(month: string): string {
    // Se è già nel formato YYYY-MM, ritorna così
    if (month.match(/^\d{4}-\d{2}$/)) {
      return month;
    }
    // Se è nel formato YYYY-MM-DD, estrai YYYY-MM
    if (month.match(/^\d{4}-\d{2}-\d{2}$/)) {
      return month.substring(0, 7);
    }
    // Altrimenti usa il mese corrente
    return this.getCurrentMonth();
  }

  formatMonthForDatabase(month: string): string {
    // Garantisce il formato YYYY-MM-01 per il database
    if (month.match(/^\d{4}-\d{2}$/)) {
      return `${month}-01`;
    }
    if (month.match(/^\d{4}-\d{2}-\d{2}$/)) {
      return month;
    }
    // Fallback
    const now = new Date();
    return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-01`;
  }

  formatMonthDisplay(month: string): string {
    try {
      const date = new Date(this.formatMonthForDatabase(month));
      return date.toLocaleDateString('it-IT', { month: 'long', year: 'numeric' });
    } catch {
      return month;
    }
  }

  formatCurrency(amount: number): string {
    return `€${amount.toFixed(2).replace('.', ',')}`;
  }

  getSupplierName(supplierId: string | null): string {
    if (!supplierId) return 'Nessun fornitore';
    const supplier = this.suppliers.find(s => s.id === supplierId);
    return supplier ? supplier.company_name : 'Fornitore sconosciuto';
  }

  // Gestione Modal
  openAddExpenseModal() {
    this.editingExpense = null;
    this.expenseForm = {
      name: '',
      amount: 0,
      type: 'fissa',
      category: '',
      month: this.formatMonthForInput(this.selectedMonth),
      notes: '',
      supplier_id: null,
      template_id: null
    };
    this.showExpenseModal = true;
  }

  openEditExpenseModal(expense: Expense) {
    console.log('📝 Opening edit modal for expense:', {
      id: expense.id,
      name: expense.name,
      template_id: expense.template_id,
      month: expense.month,
      amount: expense.amount
    });

    this.editingExpense = expense;
    this.expenseForm = {
      name: expense.name,
      amount: expense.amount,
      type: expense.type,
      category: expense.category,
      month: this.formatMonthForInput(expense.month),
      notes: expense.notes || '',
      supplier_id: expense.supplier_id || null,
      template_id: expense.template_id || null  // IMPORTANTE: mantieni il template_id
    };
    this.showExpenseModal = true;
  }

  openCategoryModal() {
    this.categoryForm = {
      name: '',
      type: 'entrambi'
    };
    this.showCategoryModal = true;
  }

  openSupplierModal() {
    this.supplierForm = {
      company_name: '',
      contact_name: '',
      email: '',
      phone: '',
      address: '',
      description: ''
    };
    this.showSupplierModal = true;
  }

  closeExpenseModal() {
    this.showExpenseModal = false;
    this.editingExpense = null;
  }

  closeMonthsModal() {
    this.showMonthsModal = false;
  }

  closeCategoryModal() {
    this.showCategoryModal = false;
  }

  closeSupplierModal() {
    this.showSupplierModal = false;
  }

  // CRUD Operations - VERSIONE SEMPLIFICATA E CORRETTA
  async saveExpense() {
    console.log('💾 Starting saveExpense...');
    console.log('📋 Form data:', this.expenseForm);
    console.log('✏️ Editing expense:', this.editingExpense);

    // Validazione
    if (!this.expenseForm.name || !this.expenseForm.amount || !this.expenseForm.category) {
      console.log('❌ Validation failed: missing required fields');
      alert('Compila tutti i campi obbligatori: Nome, Importo e Categoria');
      return;
    }

    if (this.expenseForm.amount <= 0) {
      console.log('❌ Validation failed: amount must be > 0');
      alert('L\'importo deve essere maggiore di 0');
      return;
    }

    try {
      const expenseData = {
        ...this.expenseForm,
        month: this.formatMonthForDatabase(this.expenseForm.month),
        // Aggiungi automaticamente is_recurring in base al tipo
        is_recurring: this.expenseForm.type === 'fissa'
      };

      console.log('📤 Expense data to save:', expenseData);
      console.log('🔁 Is recurring (auto-determined):', expenseData.is_recurring);

      if (this.editingExpense) {
        // MODIFICA SPESA ESISTENTE
        console.log('🔄 Updating existing expense:', this.editingExpense.id);

        // PRIMA FASE: Salva sempre la modifica per il mese corrente
        const confirmSave = confirm(
          `Vuoi salvare le modifiche per la spesa "${this.editingExpense.name}"?`
        );

        if (!confirmSave) {
          console.log('❌ Save cancelled by user');
          return;
        }

        // Salva la modifica per il mese corrente
        const updateData = {
          ...expenseData,
          template_id: this.editingExpense.template_id || null
        };

        console.log('📝 Saving update for current month:', updateData);
        const success = await this.expenseService.update(this.editingExpense.id, updateData);

        if (!success) {
          throw new Error('Update failed');
        }

        console.log('✅ Expense updated successfully for current month');

        // SECONDA FASE: Chiedi se applicare la modifica ai mesi futuri (solo per spese fisse)
        if (this.editingExpense.type === 'fissa' && expenseData.type === 'fissa') {
          // La spesa era e rimane fissa (ricorrente)
          this.showFutureMonthsConfirm = true;
          this.pendingExpenseUpdate = {
            expenseId: this.editingExpense.id,
            expenseData: expenseData,
            oldTemplateId: this.editingExpense.template_id || null
          };

          // NON chiudere il modal ancora - l'utente deve rispondere alla seconda domanda
          return; // Esci dal metodo per ora
        }

        // Se siamo qui, la spesa non è ricorrente o non richiede modifica futura
        this.completeSaveOperation();

      } else {
        // NUOVA SPESA
        console.log('🆕 Creating new expense');

        const confirmSave = confirm(
          `Vuoi creare la nuova spesa "${expenseData.name}"?`
        );

        if (!confirmSave) {
          console.log('❌ Save cancelled by user');
          return;
        }

        if (expenseData.type === 'fissa') {
          // Spesa fissa = automaticamente ricorrente
          const templateData = {
            name: expenseData.name,
            amount: expenseData.amount,
            type: expenseData.type,
            category: expenseData.category,
            notes: expenseData.notes || '',
            supplier_id: expenseData.supplier_id,
            start_month: expenseData.month
          };

          console.log('📋 Creating recurring template for fixed expense:', templateData);
          const template = await this.expenseService.createRecurringTemplate(templateData);

          if (template) {
            expenseData.template_id = template.id;
            const result = await this.expenseService.create(expenseData);

            if (result) {
              console.log('✅ Fixed (recurring) expense created with template');
              this.showSuccessAlert('Spesa fissa (ricorrente) creata con successo!');
            }
          }
        } else {
          // Spesa variabile = non ricorrente
          expenseData.is_recurring = false;
          expenseData.template_id = null;

          const result = await this.expenseService.create(expenseData);

          if (result) {
            console.log('✅ Variable (non-recurring) expense created');
            this.showSuccessAlert('Spesa variabile creata con successo!');
          }
        }

        this.completeSaveOperation();
      }

    } catch (error) {
      console.error('❌ Error saving expense:', error);
      this.showErrorAlert('Errore nel salvataggio della spesa: ' + (error as any).message);
    }
  }

  // Aggiungi questi nuovi metodi alla tua classe
  public async applyToFutureMonths(): Promise<void> {
    if (!this.pendingExpenseUpdate) return;

    try {
      const { expenseData, oldTemplateId } = this.pendingExpenseUpdate;

      // Crea un nuovo template per i mesi futuri
      const nextMonth = this.getNextMonth(expenseData.month);
      const templateData = {
        name: expenseData.name,
        amount: expenseData.amount,
        type: expenseData.type,
        category: expenseData.category,
        notes: expenseData.notes || '',
        supplier_id: expenseData.supplier_id,
        start_month: nextMonth
      };

      console.log('📋 Creating template for future months:', templateData);
      const newTemplate = await this.expenseService.createRecurringTemplate(templateData);

      if (newTemplate) {
        // Disattiva il vecchio template
        if (oldTemplateId) {
          await this.expenseService.updateRecurringTemplate(oldTemplateId, {
            is_active: false,
            end_month: expenseData.month
          });
        }

        // Aggiorna la spesa corrente con il nuovo template_id
        await this.expenseService.update(this.pendingExpenseUpdate.expenseId, {
          template_id: newTemplate.id
        });

        console.log('✅ Created new template for future months');
        this.showSuccessAlert('Modifica applicata a tutti i mesi futuri!');
      }
    } catch (error) {
      console.error('❌ Error applying to future months:', error);
      this.showErrorAlert('Errore nell\'applicazione ai mesi futuri: ' + (error as any).message);
    } finally {
      this.completeSaveOperation();
    }
  }

  public async onlyCurrentMonth(): Promise<void> {
    try {
      console.log('✅ Modification applied only to current month');
      this.showSuccessAlert('Modifica applicata solo al mese corrente.');
    } finally {
      this.completeSaveOperation();
    }
  }

  private completeSaveOperation(): void {
    // Pulisci gli stati temporanei
    this.pendingExpenseUpdate = null;
    this.showFutureMonthsConfirm = false;
    this.showExpenseModal = false;
    this.editingExpense = null;

    // Ricarica i dati
    this.loadExpenses();
  }

  private showSuccessAlert(message: string): void {
    // Puoi usare un toast o un alert più bello qui
    alert(message);
  }

  private showErrorAlert(message: string): void {
    alert(message);
  }

  async saveCategory() {
    if (!this.categoryForm.name) {
      alert('Inserisci un nome per la categoria');
      return;
    }

    try {
      const categoryData = {
        ...this.categoryForm,
        is_active: true
      };
      await this.expenseService.createCategory(categoryData);
      this.closeCategoryModal();
      await this.loadCategories();
      alert('Categoria creata con successo!');
    } catch (error) {
      console.error('Error saving category:', error);
      alert('Errore nella creazione della categoria');
    }
  }

  async saveSupplier() {
    if (!this.supplierForm.company_name) {
      alert('Inserisci il nome della ditta fornitrice');
      return;
    }

    try {
      const supplierData = {
        ...this.supplierForm,
        user_id: null,
        is_platform_supplier: false,
        is_approved: true
      };

      await this.supplierService.createSupplier(supplierData);
      this.closeSupplierModal();
      await this.loadSuppliers();
      alert('Fornitore creato con successo!');
    } catch (error) {
      console.error('Error saving supplier:', error);
      alert('Errore nella creazione del fornitore');
    }
  }

  openMonthsModal() {
    this.showMonthsModal = true;
  }

  formatMonth(month: string): string {
    return this.formatMonthDisplay(month);
  }

  async deleteExpense(expense: Expense) {
    if (confirm(`Sei sicuro di voler disattivare la spesa "${expense.name}"?`)) {
      try {
        // Usa soft delete invece di eliminazione fisica
        const success = await this.expenseService.update(expense.id, {
          deleted_at: new Date().toISOString()
        });

        if (success) {
          await this.loadExpenses();
          alert('Spesa disattivata con successo!');
        } else {
          throw new Error('Eliminazione non riuscita');
        }
      } catch (error) {
        console.error('Error deleting expense:', error);
        alert('Errore nella disattivazione della spesa');
      }
    }
  }


  // Cambia mese
  async changeMonth(month: string) {
    console.log('📅 Changing month to:', month);
    this.selectedMonth = month;
    this.viewMode = 'monthly';
    await this.loadExpenses();

    // Ricarica anche le spese disattivate se la sezione è visibile
    if (this.showDeletedSection) {
      await this.loadDeletedExpenses();
    }

    this.closeMonthsModal();
  }

  // Cambia vista
  async changeViewMode(mode: 'monthly' | 'all') {
    this.viewMode = mode;
    await this.loadExpenses();

    // Ricarica anche le spese disattivate se la sezione è visibile
    if (this.showDeletedSection) {
      await this.loadDeletedExpenses();
    }
  }

  // Aggiungi un metodo per formattare la data di eliminazione
  formatDeletedDate(dateString: string | null | undefined): string {
    if (!dateString) return 'Non eliminata';

    try {
      const date = new Date(dateString);
      return date.toLocaleDateString('it-IT', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch {
      return dateString;
    }
  }


  // Filtra categorie in base al tipo selezionato
  onExpenseTypeChange() {
    this.expenseForm.category = '';
  }

  async deactivateRecurringTemplate(templateId: string) {
    if (confirm('Vuoi disattivare questo template ricorrente? Le spese già generate rimarranno ma non se ne genereranno di nuove.')) {
      try {
        const success = await this.expenseService.updateRecurringTemplate(templateId, { is_active: false });
        if (success) {
          await this.expenseService.loadRecurringTemplates();
          alert('Template disattivato con successo');
        }
      } catch (error) {
        console.error('Error deactivating template:', error);
        alert('Errore nella disattivazione del template');
      }
    }
  }

  // Debug helper
  debugExpenses() {
    console.log('🔍 DEBUG - Current expenses:', this.expenses);
    console.log('🔍 DEBUG - Selected month:', this.selectedMonth);
    console.log('🔍 DEBUG - Filtered expenses:', this.filteredExpenses);
  }

  private getNextMonth(month: string): string {
    try {
      // Se il mese è già nel formato YYYY-MM-DD
      if (month.match(/^\d{4}-\d{2}-\d{2}$/)) {
        const date = new Date(month);
        date.setMonth(date.getMonth() + 1);
        return date.toISOString().split('T')[0];
      }

      // Se è nel formato YYYY-MM
      if (month.match(/^\d{4}-\d{2}$/)) {
        const date = new Date(`${month}-01`);
        date.setMonth(date.getMonth() + 1);
        return date.toISOString().split('T')[0];
      }

      // Fallback: usa la data corrente + 1 mese
      const date = new Date();
      date.setMonth(date.getMonth() + 1);
      return date.toISOString().split('T')[0];
    } catch (error) {
      console.error('❌ Error calculating next month:', error);
      // Fallback: ritorna il mese successivo dalla data corrente
      const date = new Date();
      date.setMonth(date.getMonth() + 1);
      return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-01`;
    }
  }

  async toggleExpenseStatus(expense: Expense) {
    const isCurrentlyActive = expense.is_active && expense.deleted_at === null;
    const action = isCurrentlyActive ? 'disattivare' : 'attivare';
    const statusText = isCurrentlyActive ? 'disattivata' : 'attivata';

    if (!confirm(`Vuoi ${action} la spesa "${expense.name}"?`)) {
      return;
    }

    try {
      console.log(`🔄 Cambiando stato della spesa "${expense.name}" da attiva=${isCurrentlyActive} a attiva=${!isCurrentlyActive}`);

      const updateData = isCurrentlyActive
        ? {
          deleted_at: new Date().toISOString(),
          is_active: false
        }
        : {
          deleted_at: null,
          is_active: true
        };

      const success = await this.expenseService.update(expense.id, updateData);

      if (success) {
        // Aggiorna le liste locali invece di ricaricare tutto
        if (isCurrentlyActive) {
          // Se stiamo disattivando, aggiungi alla lista disattivate
          this.deletedExpenses = [...this.deletedExpenses, { ...expense, ...updateData }];
          // Rimuovi dalle spese attive
          this.expenses = this.expenses.filter(e => e.id !== expense.id);
        } else {
          // Se stiamo attivando, aggiungi alle spese attive
          this.expenses = [...this.expenses, { ...expense, ...updateData }];
          // Rimuovi dalle spese disattivate
          this.deletedExpenses = this.deletedExpenses.filter(e => e.id !== expense.id);
        }

        console.log(`✅ Spesa ${statusText}:`, expense.name);
        alert(`Spesa ${statusText} con successo!`);
      } else {
        throw new Error('Operazione non riuscita');
      }
    } catch (error) {
      console.error('❌ Errore nel cambiamento di stato:', error);
      alert('Errore nel cambiamento di stato della spesa');
    }
  }

  toggleTemplatesView() {
    this.showAllTemplates = !this.showAllTemplates;
  }

  // Metodi per calcolare le statistiche delle spese disattivate
  get deletedExpensesTotal(): number {
    return this.deletedExpenses.reduce((sum, exp) => sum + exp.amount, 0);
  }

  get deletedFixedExpensesCount(): number {
    return this.deletedExpenses.filter(e => e.type === 'fissa').length;
  }

  get deletedVariableExpensesCount(): number {
    return this.deletedExpenses.filter(e => e.type === 'variabile').length;
  }

  // Aggiungi anche questo getter per ottenere le spese disattivate filtrate
  get filteredDeletedExpenses(): Expense[] {
    let filtered = this.deletedExpenses;

    // Applica i filtri simili a quelli delle spese attive
    if (this.viewMode === 'monthly') {
      filtered = filtered.filter(expense =>
        expense.month.startsWith(this.selectedMonth.substring(0, 7))
      );
    }

    if (this.searchTerm) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(expense =>
        expense.name.toLowerCase().includes(term) ||
        expense.category.toLowerCase().includes(term) ||
        (expense.notes && expense.notes.toLowerCase().includes(term))
      );
    }

    return filtered;
  }

  async permanentlyDeleteExpense(expense: Expense) {
    if (confirm(`Sei sicuro di voler eliminare definitivamente la spesa "${expense.name}"?\nQuesta azione è irreversibile e non potrai recuperare i dati!`)) {
      try {
        // Chiama il servizio per eliminazione definitiva
        // Prima devi aggiungere questo metodo al servizio expense.service.ts
        const success = await this.expenseService.hardDelete(expense.id);

        if (success) {
          // Rimuovi dalla lista locale
          this.deletedExpenses = this.deletedExpenses.filter(e => e.id !== expense.id);
          alert('Spesa eliminata definitivamente!');
        } else {
          throw new Error('Eliminazione non riuscita');
        }
      } catch (error) {
        console.error('❌ Error permanently deleting expense:', error);
        alert('Errore nell\'eliminazione definitiva della spesa');
      }
    }
  }

}